from dataclasses import dataclass, field
from enum import Enum
from typing import Dict, List, Optional


class BudgetState(str, Enum):
    NORMAL = "normal"
    CAUTION = "caution"
    FREEZE = "freeze"
    EXHAUSTED = "exhausted"


class DeploymentType(str, Enum):
    FEATURE = "feature"
    BUGFIX = "bugfix"
    HOTFIX = "hotfix"
    SECURITY = "security"
    MODEL_UPDATE = "model_update"
    INFRA = "infra"
    ROLLBACK = "rollback"


@dataclass
class DeploymentDecision:
    allowed: bool
    requires_approval: bool
    approver: Optional[str]
    reason: str


# Policy table: (BudgetState, DeploymentType) -> DeploymentDecision
POLICY: Dict[tuple, DeploymentDecision] = {
    # NORMAL: everything allowed
    **{
        (BudgetState.NORMAL, dt): DeploymentDecision(
            allowed=True, requires_approval=False, approver=None, reason="Budget healthy."
        )
        for dt in DeploymentType
    },
    # CAUTION: high-risk types need approval
    (BudgetState.CAUTION, DeploymentType.FEATURE): DeploymentDecision(
        allowed=True, requires_approval=True, approver="SRE on-call",
        reason="Feature releases require SRE sign-off during caution period."
    ),
    (BudgetState.CAUTION, DeploymentType.MODEL_UPDATE): DeploymentDecision(
        allowed=True, requires_approval=True, approver="SRE on-call",
        reason="Model updates must use staged rollout during caution period."
    ),
    (BudgetState.CAUTION, DeploymentType.BUGFIX): DeploymentDecision(
        allowed=True, requires_approval=False, approver=None, reason="Bugfixes allowed in caution."
    ),
    (BudgetState.CAUTION, DeploymentType.HOTFIX): DeploymentDecision(
        allowed=True, requires_approval=False, approver=None, reason="Hotfixes always allowed."
    ),
    (BudgetState.CAUTION, DeploymentType.SECURITY): DeploymentDecision(
        allowed=True, requires_approval=False, approver=None, reason="Security patches always allowed."
    ),
    (BudgetState.CAUTION, DeploymentType.INFRA): DeploymentDecision(
        allowed=True, requires_approval=True, approver="SRE on-call",
        reason="Infrastructure changes need review during caution."
    ),
    (BudgetState.CAUTION, DeploymentType.ROLLBACK): DeploymentDecision(
        allowed=True, requires_approval=False, approver=None, reason="Rollbacks always allowed."
    ),
    # FREEZE: only hotfixes and security
    (BudgetState.FREEZE, DeploymentType.HOTFIX): DeploymentDecision(
        allowed=True, requires_approval=True, approver="SRE on-call",
        reason="Hotfixes allowed in freeze with SRE sign-off."
    ),
    (BudgetState.FREEZE, DeploymentType.SECURITY): DeploymentDecision(
        allowed=True, requires_approval=True, approver="SRE on-call",
        reason="Security CVE patches allowed in freeze with SRE sign-off."
    ),
    (BudgetState.FREEZE, DeploymentType.ROLLBACK): DeploymentDecision(
        allowed=True, requires_approval=False, approver=None, reason="Rollbacks always allowed."
    ),
    (BudgetState.FREEZE, DeploymentType.FEATURE): DeploymentDecision(
        allowed=False, requires_approval=False, approver="Engineering Director (exception only)",
        reason="Feature deployments blocked during freeze."
    ),
    (BudgetState.FREEZE, DeploymentType.BUGFIX): DeploymentDecision(
        allowed=False, requires_approval=False, approver="Engineering Director (exception only)",
        reason="Bugfixes blocked during freeze unless tied to reliability fix."
    ),
    (BudgetState.FREEZE, DeploymentType.MODEL_UPDATE): DeploymentDecision(
        allowed=False, requires_approval=False, approver="Engineering Director (exception only)",
        reason="Model updates blocked during freeze."
    ),
    (BudgetState.FREEZE, DeploymentType.INFRA): DeploymentDecision(
        allowed=False, requires_approval=False, approver="Engineering Director (exception only)",
        reason="Infrastructure changes blocked during freeze."
    ),
    # EXHAUSTED: only rollbacks
    **{
        (BudgetState.EXHAUSTED, dt): DeploymentDecision(
            allowed=False, requires_approval=False, approver="VP of Engineering",
            reason="Budget exhausted: all deployments blocked. SLA breach imminent."
        )
        for dt in DeploymentType if dt != DeploymentType.ROLLBACK
    },
    (BudgetState.EXHAUSTED, DeploymentType.ROLLBACK): DeploymentDecision(
        allowed=True, requires_approval=False, approver=None,
        reason="Emergency rollbacks always permitted to restore service."
    ),
}


def get_budget_state(remaining_pct: float) -> BudgetState:
    if remaining_pct <= 0:
        return BudgetState.EXHAUSTED
    elif remaining_pct < 10:
        return BudgetState.FREEZE
    elif remaining_pct < 50:
        return BudgetState.CAUTION
    return BudgetState.NORMAL


def check_deployment(
    remaining_pct: float,
    deployment_type: DeploymentType,
) -> DeploymentDecision:
    state = get_budget_state(remaining_pct)
    return POLICY.get(
        (state, deployment_type),
        DeploymentDecision(
            allowed=False, requires_approval=False,
            approver=None, reason="No policy defined for this (state, type) pair."
        ),
    )


if __name__ == "__main__":
    for pct in [80.0, 30.0, 5.0, 0.0]:
        state = get_budget_state(pct)
        decision = check_deployment(pct, DeploymentType.FEATURE)
        print(f"Budget {pct}% ({state.value}): feature deploy = "
              f"{'ALLOWED' if decision.allowed else 'BLOCKED'}"
              f"{' — needs: ' + decision.approver if decision.approver else ''} "
              f"({decision.reason})")
